(6203, 'https://support.google.com/chrome/answer/2364824', 'Manage Chrome with multiple profiles - Computer - Google Chrome Help', 'With profiles, you can keep all your Chrome info separate, like bookmarks, history, passwords, and other settings. Profiles are ideal when you want to: Share a computer with multiple people. Ke', '', 0),
(6204, 'https://myaccount.google.com/activitycontrols', 'Sign in - Google Accounts', '', '', 0),
(6205, 'https://support.google.com/chrome/answer/6130773', 'Browse Chrome as a guest - Computer - Google Chrome Help', 'When you use a public computer or share a computer with others, websites that you visit in Guest mode won’t appear in the browser history. In Guest mode, you won\'t find or be able to change any other', '', 0),
(6206, 'https://support.google.com/chromebook/answer/1057090', 'Use a Chromebook as a guest - Chromebook Help', 'To use a Chromebook without signing in to your Google Account, you can browse as a guest. Guest browsing is useful for temporary use or sharing a device, like if you want to: Let someone borrow', '', 0),
(6207, 'https://support.apple.com/kb/ph21413', 'Browse privately in Safari on Mac - Apple Support', 'In Safari on your Mac, browse without leaving a record of the websites you visit.', '', 0),
(6208, 'https://support.mozilla.org/en-US/kb/private-browsing-use-firefox-without-history', 'Private Browsing - Use Firefox without saving history | Firefox Help', 'Firefox Private Browsing is great for viewing websites without saving things such as cookies, temp files and a history of the pages you visit.', '', 0),
(6209, 'https://support.microsoft.com/en-us/help/4026200/windows-browse-inprivate-in-microsoft-edge', 'Browse InPrivate in Microsoft Edge - Microsoft Support', 'When you use InPrivate tabs or windows, your browsing data isn\'t saved on your PC once you\'re done.', '', 0),
(6210, 'https://support.google.com/accounts/answer/32050', 'Clear cache & cookies - Computer - Google Account Help', 'When you use a browser, like Chrome, it saves some information from websites in its cache and cookies. Clearing them fixes certain problems, like loading or formatting issues on sites. In Chrome', '', 0),
(6211, 'https://support.google.com/chrome/answer/95589', 'Check or delete your Chrome browsing history - Android - Google Chrome Help', 'Websites you’ve visited are recorded in your browsing history. You can check or delete your browsing history, and find related searches in Chrome. You can also resume browsing sessions on other device', '', 0),
(6212, 'https://support.google.com/accounts/answer/2917834?visit_id=638886918789736836-1520331392&p=signin_privatebrowsing&hl=en&rd=1&co=GENIE.Platform%3DDesktop', 'Sign in on a device that\'s not yours - Computer - Google Account Help', 'If you sign in temporarily on a computer, phone, or tablet that doesn\'t belong to you, use a private browsing window. For example: A public computer that\'s available to lots of people, like at a', '', 0),
