(6367, 'https://www.radiofrance.fr/', 'Radio France | Écoutez en ligne vos radios', 'Retrouvez les radios en direct et replay, les podcasts originaux et la musique de France Inter, franceinfo, ici, France Culture, France Musique, Fip, Mouv\'. Écoutez en ligne tous les programmes de Radio France.', '', 0),
(6368, 'https://www.radiofrance.fr/franceinter', 'France Inter – Première radio d\'actualité généraliste et culturelle', 'Vous êtes bien sur France Inter ! Suivez les infos du jour et l\'actualité culturelle. Écoutez la radio en replay et découvrez des podcasts inédits.', '', 0),
(6369, 'https://www.radiofrance.fr/franceinfo', 'Écouter franceinfo en direct, la radio d\'info de Radio France', 'En direct et replay, écoutez franceinfo sur le site et l\'application mobile Radio France. Toute l\'actualité, dernières infos et archives en podcasts.', '', 0),
(6370, 'https://www.radiofrance.fr/francebleu', 'Écouter ici, votre radio locale en direct et podcasts – Radio France', 'Toute la vie des régions est sur votre radio locale ici : écoutez les infos locales, reportages, initiatives, événements, idées de sorties et loisirs.', '', 0),
(6371, 'https://www.radiofrance.fr/franceculture', 'France Culture – Écouter la radio en direct et podcasts gratuitement', 'S\'informer, développer sa curiosité et apprendre chaque jour avec les émissions de France Culture. Écoutez la radio en direct, en replay et podcasts.', '', 0),
(6372, 'https://www.radiofrance.fr/francemusique', 'France Musique – Écouter la radio en direct et podcasts', 'Tout l\'univers de la musique Classique, Jazz, Contemporaine et plus. Écoutez tous les programmes de France Musique en direct, replay radio et podcasts.', '', 0),
(6373, 'https://www.radiofrance.fr/fip', 'FIP – Écouter la radio en direct et les radios thématiques', 'Tout l\'univers musical de FIP, sélection de titres Jazz, Electro, Rock, Pop, Groove et bien plus. Écoutez la radio en direct et les radios thématiques.', '', 0),
(6374, 'https://www.radiofrance.fr/mouv', 'Mouv\' Radio – Musique Rap & Hip Hop Nation', 'Tout l\'univers de la musique Rap & Hip Hop Nation, l\'actualité du moment et plus encore sur Mouv\'. Écoute gratuitement les streams radios en ligne.', '', 0),
(6375, 'https://www.radiofrance.fr/podcasts', 'Écouter des podcasts : le meilleur de Radio France', 'A la recherche d\'un podcast à écouter ? Explorez le catalogue de Radio France : sélection des meilleurs podcasts. Écoutez gratuitement des émissions et séries audio passionnantes.', '', 0),
(6376, 'https://www.radiofrance.fr/sciences-savoirs', 'Sciences & Savoirs : Tous les podcasts pour se cultiver et apprendre | Radio France', 'Écoutez gratuitement les émissions et podcasts de la catégorie Sciences & Savoirs. Toutes les séries audio pour apprendre et se cultiver en ligne.', '', 0),
(6377, 'https://www.radiofrance.fr/societe', 'Société : podcasts à écouter, dernières actualités et infos société | Radio France', 'Retrouvez tous les podcasts à écouter et les articles d\'actualité pour comprendre les mouvements de la société française, ses débats et ses réformes.', '', 0),
(6378, 'https://www.radiofrance.fr/environnement', 'Environnement : Toutes les actualités, analyses et débats en podcasts | Radio France', 'Écoutez les derniers podcasts sur l\'environnement, suivez l\'actualité en direct. Explications scientifiques, analyse des enjeux et solutions concrètes.', '', 0),
(6379, 'https://www.radiofrance.fr/arts-divertissements', 'Arts : podcasts sur les actualités artistiques et les divertissements | Radio France', 'Toute l\'actualité Arts et Divertissement sur Radio France. Podcasts à écouter gratuitement en ligne et depuis l\'application, avec les dernières actualités et débats.', '', 0),
(6380, 'https://www.radiofrance.fr/monde', 'Actualités internationales et infos monde en direct – Radio France', 'Toutes les infos internationales et l\'actualité dans le monde : podcasts, dossiers et décryptages par les reporters et journalistes de Radio France.', '', 0),
(6381, 'https://www.radiofrance.fr/politique', 'Politique : Tous les podcasts et l\'actualité politique en France | Radio France', 'Écoutez les émissions politiques et les interviews en direct, en replay ou podcast. Débats, analyses et décryptages de la vie politique française.', '', 0),
(6382, 'https://www.radiofrance.fr/economie', 'Économie : podcasts et actualités économiques de Radio France', 'Écoutez les derniers podcasts, interviews et analyses sur l\'économie. Toute l\'actualité économique, enjeux pour les entreprises, théories et réformes.', '', 0),
(6383, 'https://www.radiofrance.fr/cellule-investigation', 'Cellule investigation de Radio France', 'Découvrez les révélations et analyses menées par la Cellule d\'investigation de Radio France. Ecouter leurs enquêtes à travers nos podcasts', '', 0),
(6384, 'https://www.radiofrance.fr/vie-quotidienne', 'Vie quotidienne : podcasts sur toutes vos activités de loisirs | Radio France', 'Écoutez gratuitement des podcasts sur la cuisine, les activités de loisirs créatives et culturelles, toutes les émissions de vie quotidienne en replay.', '', 0),
(6385, 'https://www.radiofrance.fr/bien-etre', 'Bien-être : podcasts pour prendre soin de soi et le mieux-être | Radio France', 'Écoutez ici les derniers podcasts de Radio France sur le bien-être et le mieux-être, témoignages et récits, réponses de spécialistes en psychologie.', '', 0),
(6386, 'https://www.radiofrance.fr/podcasts/enfants', 'Histoires pour enfants à écouter, podcasts jeunesse | Radio France', 'Écoutez les histoires audio et émissions pour enfants de France Inter, France Culture, France Musique et franceinfo. Retrouvez les contes Oli, Les Odyssées, Les Zinstrus et bien d’autres histoires pour enfants et ados, à écouter gratuitement.', '', 0),
(6387, 'https://www.radiofrance.fr/sports', 'Sport : Toute l\'actualité sportive et les meilleurs podcasts sports | Radio France', 'Vivez le sport en direct et replay : meilleurs moments, portraits de champions, reportages, interviews et analyses à écouter gratuitement en podcast.', '', 0),
(6388, 'https://www.radiofrance.fr/musique', 'Actualités musicales : Toute l\'info musique et les meilleurs podcasts | Radio France', 'Écoutez ici tous les podcasts qui parlent de musique et suivez l\'actualité musicale : interviews d\'artistes, sorties d\'albums, playlists et concerts.', '', 0),
(6389, 'https://www.radiofrance.fr/ecouter-musique', 'Écouter de la musique gratuitement sur Radio France', 'Écoutez en illimité et gratuitement de la musique : tous les artistes, les radios, des playlists inédites et les vidéos de concerts Radio France.', '', 0),
(6390, 'https://www.radiofrance.fr/concerts', 'Regardez et écoutez des milliers de concerts – Radio France', 'Écoutez et regardez gratuitement tous les concerts Radio France de musique classique, pop, rock, jazz disponibles en streaming audio et vidéo.', '', 0),
(6391, 'https://www.radiofrance.fr/podcasts/fictions', 'Podcasts Fictions : les meilleures fictions radiophoniques par Radio France', 'Podcasts Fictions', '', 0),
(6392, 'https://www.radiofrance.fr/info', 'Podcasts sur l\'info en France en direct, les actualités du jour | Radio France', 'Toute l\'actualité Info sur Radio France. Podcasts à écouter gratuitement en ligne et depuis l\'application, avec les dernières actualités et débats.', '', 0),
(6393, 'https://www.radiofrance.fr/sujets/des-podcasts-pour-apprendre-et-reviser', 'Des podcasts pour apprendre et réviser : toute l\'actualité et les podcasts à écouter | Radio France', 'Toute l\'actualité Des podcasts pour apprendre et réviser sur Radio France. Podcasts à écouter gratuitement en ligne et depuis l\'application, avec les dernières actualités et débats.', '', 0),
(6394, 'https://www.radiofrance.fr/podcasts/true-crime', 'True crime : podcasts de crimes et histoires vraies à écouter | Radio France', 'Histoires vraies, témoignages, enquêtes : retours sur les grandes affaires criminelles qui ont défrayé la chronique. Des faits divers terrifiants et énigmatiques à écouter et réécouter gratuitement.', '', 0),
(6395, 'https://www.radiofrance.fr/sciences-savoirs/histoire', 'Histoire : Tous les podcasts et émissions historiques en replay | Radio France', 'Écoutez gratuitement les podcasts de Radio France sur l\'histoire. Découvrez des séries audio inédites et des émissions historiques passionnantes.', '', 0),
(6396, 'https://www.radiofrance.fr/recherche', 'Rechercher un podcast ou une archive d\'actualité – Radio France', 'Effectuez une recherche dans le catalogue de podcasts de Radio France : toutes les archives, concerts, articles et dossiers, émissions de radio.', '', 0),
(6397, 'https://www.radiofrance.fr/franceculture/podcasts/le-magazine-du-week-end', 'Le Magazine du week-end : podcast et émission en replay | France Culture', 'Le Magazine du week-end de France Culture prend le temps de procéder à un décryptage patient et exigeant des temps forts de l’actualité française, comme internationale, à travers des entretiens et des débats.', '', 0),
(6398, 'https://www.radiofrance.fr/franceculture/podcasts/le-magazine-du-week-end/etats-unis-l-affaire-epstein-se-retourne-t-elle-contre-donald-trump-1932353', 'États-Unis : l\'affaire Epstein se retourne-t-elle contre Donald Trump ? | France Culture', 'C’est un scandale politique et judiciaire, une affaire de trafic sexuel qui continue d’empoisonner la vie politique américaine. L’affaire Epstein provoque des remous dans la base électorale de Donald Trump sur fond de théories du complot. Le président américain pourrait-il en sortir fragilisé ?', '', 0),
(6399, 'https://www.radiofrance.fr/franceinter/podcasts/le-journal-de-18h', 'Le journal de 18h : podcast et émission en replay | France Inter', 'Le rendez-vous d\'information du début de soirée sur France Inter.', '', 0),
(6400, 'https://www.radiofrance.fr/franceculture/podcasts/journal-de-18h', 'Journal de 18h : podcast et émission en replay | France Culture', 'Journal présenté par Aurélie Kieffer et Nicolas Balu.', '', 0),
(6401, 'https://www.radiofrance.fr/franceculture/podcasts/journal-de-18h/journal-de-18h-emission-du-lundi-21-juillet-2025-1575900', 'JOURNAL DE 18H, émission du lundi 21 juillet 2025 | France Culture', '', '', 0),
(6402, 'https://www.radiofrance.fr/francemusique/podcasts/retour-de-plage', 'Retour de plage : podcast et émission en replay | France Musique', 'Jazz, soul, funk, airs latins, pop, musique brésilienne, chanson française, standards revisités… Par Thierry Jousse en juillet et Laurent Valero en août.', '', 0),
(6403, 'https://www.radiofrance.fr/francemusique/podcasts/retour-de-plage/retour-de-plage-sammy-davis-jr-le-crooner-ideal-1070543', 'Retour de plage ... Sammy Davis Jr, Le Crooner idéal | France Musique', '\"Personnalité atypique, militant anti-ségrégationniste, membre du Rat Pack, avec Frank Sinatra et Dean Martin, Sammy Davis Jr était surtout un admirable crooner, non dénué de fantaisie. La preuve avec un programme qui lui est entièrement consacré… \" Thierry Jousse', '', 0),
(6404, 'https://www.radiofrance.fr/mouv/podcasts/mouv-summer-club', 'Mouv\' Summer Club : podcast et émission en replay | Mouv\'', 'Jules Thiebaut et Nalla vous offrent les meilleurs sons et la meilleure  humeuree l\'été', '', 0),
(6405, 'https://www.radiofrance.fr/sujets/depenses-publiques-budget-de-l-etat', 'Dépenses publiques – Budget de l\'État : toute l\'actualité et les podcasts à écouter | Radio France', 'Toute l\'actualité Dépenses publiques – Budget de l\'État sur Radio France. Podcasts à écouter gratuitement en ligne et depuis l\'application, avec les dernières actualités et débats.', '', 0),
(6406, 'https://www.radiofrance.fr/franceinfo/podcasts/les-documents-franceinfo/loi-duplomb-il-faut-remettre-de-la-rationalite-dans-le-debat-estime-arnaud-rousseau-le-president-de-la-fnsea-5114820', 'Loi Duplomb : il faut \"remettre de la rationalité dans le débat\", estime Arnaud Rousseau, le président de la FNSEA | franceinfo', 'La pétition contre la loi Duplomb a dépassé le million de signataires dimanche 20 juillet. Favorable à cette loi, Arnaud Rousseau, le président de la FNSEA, \"veut remettre un peu de rationalité dans ce débat qui suscite beaucoup de craintes et de peurs\".', '', 0),
(6407, 'https://www.radiofrance.fr/franceinfo/podcasts/les-documents-franceinfo', 'Les documents franceinfo : podcast et émission en replay | franceinfo', 'Reportages, témoignages, exclusivités : l\'actualité à écouter avec franceinfo.', '', 0),
(6408, 'https://www.radiofrance.fr/franceinfo/podcasts/les-documents-franceinfo/petition-pour-l-abrogation-de-la-loi-duplomb-yael-braun-pivet-favorable-a-l-organisation-d-un-debat-a-l-assemblee-1377085', 'Pétition pour l\'abrogation de la loi Duplomb : Yaël Braun-Pivet \"favorable\" à l\'organisation d\'un débat à l\'Assemblée | franceinfo', 'Avec quasiment 1 000 signatures par minute, la pétition contre la loi Duplomb connaît un succès inédit. Elle proteste notamment contre la réintroduction d\'un pesticide autorisé par l\'UE, mais interdit en France.', '', 0),
(6409, 'https://www.radiofrance.fr/franceinter/podcasts/l-info-de-france-inter/l-info-de-france-inter-2393400', 'Une pétition rassemble un million de signatures contre la loi Duplomb : et maintenant ? | France Inter', 'Elle a passé le cap du million de signatures ce dimanche, en un temps record : une pétition sur le site de l\'Assemblée nationale mobilise largement contre la loi Duplomb, accusée d\'être \"une aberration scientifique, éthique, environnementale et sanitaire\".', '', 0),
(6410, 'https://www.radiofrance.fr/franceinter/podcasts/les-documents-france-inter', 'L\'info de France Inter : écouter le podcast et replay | France Inter', 'Les dernières informations développées par la rédaction de France Inter.', '', 0),
(6411, 'https://www.radiofrance.fr/franceinfo/podcasts/8h30-franceinfo/budget-2026-loi-duplomb-suppression-de-deux-jours-feries-le-8h30-de-sandrine-rousseau-8786032', 'Budget 2026, loi Duplomb, suppression de deux jours fériés... Le 8h30 de Sandrine Rousseau | franceinfo', 'La députée écologiste était l\'invité du \"8h30 franceinfo\", lundi 21 juillet.', '', 0),
(6412, 'https://www.radiofrance.fr/franceinfo/podcasts/8h30-franceinfo', '8h30 franceinfo : podcast et émission en replay | franceinfo', 'L\'interview politique de la matinale de franceinfo : tous les jours, un invité qui fait l\'actualité.', '', 0),
(6413, 'https://www.radiofrance.fr/franceinter/podcasts/sous-le-soleil-de-platon', 'Sous le soleil de Platon : podcast philo sur France Inter', 'PODCAST. Un rendez-vous quotidien pour parler de philosophie pratique, existentielle et intime. Écoutez sur France Inter l\'émission de Charles Pépin.', '', 0),
(6414, 'https://www.radiofrance.fr/franceculture/podcasts/serie-hildegarde-genie-cosmique', 'Hildegarde de Bingen, génie cosmique : un podcast à écouter en ligne | France Culture', 'L\'histoire se passe au Moyen Âge : une petite fille aux capacités hors normes voit le jour dans la vallée du Rhin. Elle s’appelle Hildegarde de Bingen et connaîtra un destin extraordinaire de mère abbesse, visionnaire et compositrice de génie, femme de pouvoir devenue symbole de sororité.', '', 0),
(6415, 'https://www.radiofrance.fr/francemusique/podcasts/serie-rostropovitch-le-violoncelle-en-liberte', 'Rostropovitch, le violoncelle en liberté : un podcast à écouter en ligne | France Musique', 'Mstislav Rostropovitch a joué et enregistré tout le répertoire classique, suscité des centaines de nouvelles partitions pour son instrument, le violoncelle, auprès des plus grands compositeurs de son temps.', '', 0),
(6416, 'https://www.radiofrance.fr/franceinter/podcasts/la-vie-a-portee-de-main', 'La Vie à portée de main : écouter le podcast et replay | France Inter', 'Un voyage scientifique explorant l\'évolution de la vie, de ses premières formes à la possibilité de vie extraterrestre.', '', 0),
(6417, 'https://www.radiofrance.fr/francebleu/podcasts/serie-la-ou-ils-ont-trouve-l-inspiration', 'Là où ils ont trouvé l’inspiration... : un podcast à écouter en ligne | ici', 'Marcher dans les pas de Léonard de Vinci, George Sand, Henri Rousseau, Claude Monet ou Joséphine Baker, découvrir leur demeure, les lieux où ils ont vécu et qui, peu à peu, sont devenus pour eux des lieux refuges et inspirants… donne une autre perception de leurs créations', '', 0),
(6418, 'https://www.radiofrance.fr/franceinfo/podcasts/serie-leon-marchand', 'Léon Marchand | franceinfo', 'Avec ses 4 médailles d\'Or, Léon Marchand est resté l\'un des héros des JO de Paris 2024. Portrait d\'un champion discret, plus à l\'aise dans l\'eau que sous les projecteurs, et qui à 22 ans doit désormais composer avec la notoriété due à son talent', '', 0),
(6419, 'https://www.radiofrance.fr/francebleu/podcasts/comment-occuper-les-enfants-8342688', 'Comment occuper les enfants ? : podcast et émission en replay | ici', 'Vaste question que celle de la distraction des enfants pendant les vacances... Avec notre experte Lucie Miocec, découvrez de petites astuces qui vous assurent des vacances amusantes pour tous !', '', 0),
(6420, 'https://www.radiofrance.fr/franceculture/podcasts/serie-les-accords-qui-ont-change-le-monde', 'Les accords qui ont changé le monde  : un podcast à écouter en ligne | France Culture', 'De la Colombie au Mali en passant par les Balkans, ils ont été signés pour faire advenir la paix et assurer la sécurité. D\'ambitions en désillusions, retour sur dix accords internationaux qui font à la fois l\'histoire et l\'actualité.', '', 0),
(6421, 'https://www.radiofrance.fr/franceinter/podcasts/les-jolies-vacances-d-emma', 'Les jolies vacances d\'Emma  : écouter le podcast et replay | France Inter', 'La chronique sexualité d\'Emma Becker.', '', 0),
(6422, 'https://www.radiofrance.fr/radiofrance/podcasts/selection-la-cite-de-carcassonne-en-5-podcasts', 'La Cité de Carcassonne en 5 podcasts | Radio France', 'AUDIO. Découvrez cette sélection des meilleurs podcasts à écouter gratuitement. La Cité de Carcassonne en 5 podcasts : chroniques, podcasts et émissions de radio du moment, ce qu\'il ne fallait pas manquer, extraits de l\'actualité et des archives de Radio France.', '', 0),
(6423, 'https://www.radiofrance.fr/radiofrance/podcasts/selection-l-annee-2016-en-podcasts', 'L\'année 2016 en podcasts  : une sélection des meilleurs podcasts à écouter | Radio France', 'AUDIO. Découvrez cette sélection des meilleurs podcasts à écouter gratuitement. L\'année 2016 en podcasts  : chroniques, podcasts et émissions de radio du moment, ce qu\'il ne fallait pas manquer, extraits de l\'actualité et des archives de Radio France.', '', 0),
(6424, 'https://www.radiofrance.fr/franceculture/podcasts/serie-avoir-raison-avec-louise-weiss', 'Avoir raison avec... Louise Weiss : un podcast à écouter en ligne | France Culture', 'Militante, écrivaine, journaliste et voyageuse, Louise Weiss fut de tous les combats : pour les droits des femmes, pour la paix, pour l’entente entre les nations, mais que signifie avoir raison avec \"la grand-mère de l’Europe\" ?', '', 0),
(6425, 'https://www.radiofrance.fr/francemusique/podcasts/serie-germaine-tailleferre-la-rebelle-des-annees-folles', 'Germaine Tailleferre, la rebelle des années folles  : un podcast à écouter en ligne | France Musique', 'C’est en cachette de son père que Germaine Tailleferre, pianiste prometteuse, décide d’entrer au conservatoire. Pour lui, entre le conservatoire et le trottoir, pas de différence ! Germaine va lui donner tort et décrocher tous les Premiers Prix.', '', 0),
(6426, 'https://www.radiofrance.fr/franceinter/podcasts/serie-albert-camus-une-vie-de-passion-de-pensee-et-de-combats', 'Albert Camus, une vie de passion, de pensée et de combats  : un podcast à écouter en ligne | France Inter', 'Enfance algérienne, amour avec Maria Casarès, brouille avec Sartre, et prix Nobel de littérature...  En quatre épisodes issus de l\'émission \"Autant en Emporte l’Histoire\" présentée par Stéphanie Duncan, focus sur l\'écrivain français auteur de L\'Étranger, ouvrage devenu classique de la littérature.', '', 0),
(6427, 'https://www.radiofrance.fr/franceinter/podcasts/le-code-a-change/le-code-a-change-9194623', 'Les jeux vidéo, nouveau terrain de la guerre culturelle | France Inter', 'Guerre culturelle, soft power, extrême droite : plongée dans les controverses qui agitent le monde du jeu vidéo. Olivier Mauco, docteur en sciences politiques, analyse les enjeux et les acteurs de ces affrontements.', '', 0),
(6428, 'https://www.radiofrance.fr/sports/cyclisme/tour-de-france', 'Tour de France : Toute l\'actualité en direct, replay et podcasts | Radio France', 'Toute l\'actualité Tour de France sur Radio France. Podcasts à écouter gratuitement en ligne et depuis l\'application, avec les dernières actualités et débats.', '', 0),
(6429, 'https://www.radiofrance.fr/sujets/incendies', 'Incendies : toute l\'actualité et les podcasts à écouter | Radio France', 'Toute l\'actualité Incendies sur Radio France. Podcasts à écouter gratuitement en ligne et depuis l\'application, avec les dernières actualités et débats.', '', 0),
(6430, 'https://www.radiofrance.fr/sujets/conflit-israelo-palestinien', 'Conflit israélo-palestinien : toute l\'actualité et les podcasts à écouter | Radio France', 'Toute l\'actualité Conflit israélo-palestinien sur Radio France. Podcasts à écouter gratuitement en ligne et depuis l\'application, avec les dernières actualités et débats.', '', 0),
(6431, 'https://www.radiofrance.fr/monde/amerique-nord/etats-unis', 'États-Unis : toute l\'actualité et les podcasts à écouter | Radio France', 'Toute l\'actualité États-Unis sur Radio France. Podcasts à écouter gratuitement en ligne et depuis l\'application, avec les dernières actualités et débats.', '', 0),
(6432, 'https://www.radiofrance.fr/sujets/guerre-en-ukraine', 'Guerre en Ukraine : toute l\'actualité et les podcasts à écouter | Radio France', 'Toute l\'actualité Guerre en Ukraine sur Radio France. Podcasts à écouter gratuitement en ligne et depuis l\'application, avec les dernières actualités et débats.', '', 0),
(6433, 'https://www.radiofrance.fr/franceinter/podcasts/l-info-de-france-inter/l-info-de-france-inter-9862357', 'Comment la malbouffe pèse (aussi) sur les finances publiques | France Inter', 'Les dernières études montrent que la France investit 19 milliards d\'euros par an pour compenser les dégâts sociaux, sanitaires et environnementaux de son système agroalimentaire. La prise en charge de l\'obésité pèse notamment sur les finances publiques.', '', 0),
(6434, 'https://www.radiofrance.fr/franceinter/podcasts/l-info-de-france-inter/l-info-de-france-inter-6403971', '\"J\'ai profondément honte\" : un ancien soldat israélien dénonce la \"déshumanisation\" de l\'armée | France Inter', 'Après 21 mois de guerre, un ancien soldat israélien dénonce l\'attitude des soldats d\'aujourd\'hui à Gaza. Il constate une \"déshumanisation\" qui touche l\'armée et, plus largement, la société israélienne.', '', 0),
(6435, 'https://www.radiofrance.fr/franceinter/podcasts/l-info-de-france-inter/l-info-de-france-inter-1371052', 'Microsoft va offrir à la France une réplique numérique de Notre-Dame de Paris | France Inter', 'Microsoft, plus europhile des géants de la tech américains ? La société fait officiellement ce lundi plusieurs annonces en ce sens, notamment la numérisation de la cathédrale parisienne. Brad Smith, président de Microsoft, est à Paris pour signer une convention en ce sens avec Rachida Dati.', '', 0),
(6436, 'https://www.radiofrance.fr/franceinter/podcasts/l-info-de-france-inter/l-info-de-france-inter-6584312', 'Monétiser la haine : sur les réseaux sociaux, la revanche des femmes face aux misogynes | France Inter', 'De très nombreuses créatrices de contenus reçoivent des commentaires haineux envoyés par des hommes sur les réseaux sociaux. La misogynie en ligne n\'est pas nouvelle mais certaines femmes ont décidé d\'utiliser ces messages pour se faire de l\'argent.', '', 0),
(6437, 'https://www.radiofrance.fr/franceinfo/podcasts/les-documents-franceinfo/en-tant-qu-israelien-j-ai-honte-de-ce-qui-se-passe-temoigne-un-ancien-militaire-dans-la-bande-de-gaza-6905359', '\"En tant qu\'Israélien, j\'ai honte de ce qui se passe\", témoigne un ancien militaire dans la bande de Gaza | franceinfo', 'L’État hébreu poursuit ses attaques meurtrières dans la bande de Gaza et la famine s’aggrave dans cette enclave palestinienne. Les méthodes d’Israël suscitent de plus en plus de critiques, y compris de la part d’anciens militaires israéliens. Témoignage.', '', 0),
(6438, 'https://www.radiofrance.fr/franceinfo/podcasts/les-documents-franceinfo/affaire-jubillar-selon-une-ex-compagne-qui-va-etre-entendue-cedric-jubillar-lui-a-dit-avoir-etrangle-sa-femme-3239187', 'Affaire Jubillar :  selon une ex-compagne, qui va être entendue, Cédric Jubillar lui a dit avoir étranglé sa femme : épisode  du podcast Enquêtes | franceinfo', 'AUDIO • Enquêtes, épisode  : Affaire Jubillar :  selon une ex-compagne, qui va être entendue, Cédric Jubillar lui a dit avoir étranglé sa femme. Une série inédite proposée par franceinfo. Écoutez Les documents franceinfo, et découvrez nos podcasts en ligne.', '', 0),
(6439, 'https://www.radiofrance.fr/franceinfo/podcasts/les-documents-franceinfo/loi-duplomb-les-740-000-signatures-de-la-petition-contre-la-loi-permettent-un-nouveau-debat-a-l-assemblee-nationale-5402899', 'Loi Duplomb : les 740 000 signatures de la pétition contre la loi permettent un nouveau débat à l’Assemblée nationale | franceinfo', 'Disponible depuis 10 jours sur le site internet de l\'Assemblée nationale, une pétition contre la loi Duplomb a été signée par plus de 740 000 personnes (en date du 20 juillet), au-dessus du seuil des 500 000 signatures qui permet un nouveau débat à l\'Assemblée nationale.', '', 0),
(6440, 'https://www.radiofrance.fr/franceinter/podcasts/le-zoom-de-france-inter/le-zoom-de-la-redaction-du-lundi-21-juillet-2025-2025248', 'Les dîners entre inconnus, \"ça ouvre de nouveaux horizons\" | France Inter', '[Rediffusion] France Inter s\'intéresse à ces endroits où l\'on se reparle, ces lieux de débat, de discussion. Nous avons testé le dîner entre inconnus, organisé par l\'application Timeleft.', '', 0),
(6441, 'https://www.radiofrance.fr/franceinter/podcasts/le-zoom-de-la-redaction', 'Le Zoom de France Inter : podcast et émission en replay | France Inter', '', '', 0),
(6442, 'https://www.radiofrance.fr/franceinter/podcasts/le-grand-format/le-grand-format-du-lundi-21-juillet-2025-2939989', '\"C\'est une aberration\" : le désarroi d\'un éleveur face à l’abattage de son cheptel touché par la dermatose | France Inter', 'En Savoie et Haute-Savoie, 32 foyers de contamination à la dermatose nodulaire ont été détectés. Depuis l\'apparition de cette maladie très contagieuse, l’État procède à l’abattage systématique des cheptels touchés, ce que dénoncent certains éleveurs. Reportage à Entrelacs, en Savoie.', '', 0),
(6443, 'https://www.radiofrance.fr/franceinter/podcasts/grand-angle', 'Le grand format : podcast et émission en replay | France Inter', 'Du lundi au vendredi, un reportage long diffusé dans les journaux de France Inter, sur l\'actualité du jour.', '', 0),
(6444, 'https://www.radiofrance.fr/franceculture/podcasts/culture-de-l-info/intelligence-artificielle-le-retard-relatif-du-japon-4840782', 'Intelligence artificielle : le retard relatif du Japon : épisode 9/9 du podcast L\'intelligence artificielle, une arme géopolitique | France Culture', 'AUDIO • L\'intelligence artificielle, une arme géopolitique , épisode 9/9 : Intelligence artificielle : le retard relatif du Japon. Une série inédite proposée par France Culture. Écoutez Culture de l\'info, et découvrez nos podcasts en ligne.', '', 0),
(6445, 'https://www.radiofrance.fr/franceculture/podcasts/culture-de-l-info', 'Culture de l\'info : écouter le podcast et replay | France Culture', 'Du lundi au vendredi, à 21h, un rendez-vous de 8 minutes. L’actualité du jour vue par la rédaction de France Culture, avec un focus sur une thématique que vous avez peut-être manqué dans nos journaux.', '', 0),
(6446, 'https://www.radiofrance.fr/franceinfo/podcasts/le-choix-de-franceinfo/nous-ne-sommes-pas-le-maillon-faible-de-l-armee-ukrainienne-en-immersion-avec-la-brigade-anne-de-kiev-encore-marquee-par-la-desertion-et-la-corruption-7004382', '\"Nous ne sommes pas le maillon faible de l\'armée ukrainienne\" : en immersion avec la brigade \"Anne de Kiev\" encore marquée par la désertion et la corruption | franceinfo', 'Depuis sa création en octobre 2024, cette unité, formée en France, essuie les déconvenues. Entre formation expéditive, défection des soldats et corruption, la brigade \"Anne de Kiev\" résiste.', '', 0),
(6447, 'https://www.radiofrance.fr/franceinfo/podcasts/le-choix-franceinfo', 'Le choix de franceinfo : podcast et émission en replay | franceinfo', 'Tous les matins, un reportage, un témoignage ou une enquête de la rédaction de franceinfo pour approfondir un fait d’actualité.', '', 0),
(6448, 'https://www.radiofrance.fr/franceculture/podcasts/le-journal-de-l-eco/pas-d-emission-pour-cause-de-greve-7641221', 'Nouvelle prolongation du conclave sur les retraites ? | France Culture', 'Pas de décryptage pour cause de grève.', '', 0),
(6449, 'https://www.radiofrance.fr/franceculture/podcasts/le-journal-de-l-eco', 'Le Journal de l\'éco : podcast et émission en replay | France Culture', 'Chaque matin, le décryptage d’une actualité économique.', '', 0),
(6450, 'https://www.radiofrance.fr/franceculture/podcasts/l-info-culturelle-reportages-enquetes-analyses/artistes-russes-les-positions-de-neutralite-traduisent-en-general-soit-de-l-approbation-soit-de-la-peur-9523518', 'Artistes russes : \"Les positions de neutralité traduisent, en général, soit de l\'approbation, soit de la peur\" | France Culture', 'En Russie, d\'autant plus depuis l\'invasion de l\'Ukraine, la liberté d\'expression des artistes est encadrée. Lorsqu\'ils se produisent à l\'étranger, certains dénoncent le régime, d\'autres adoptent une neutralité. Un flou qui peut autant cacher la peur de représailles qu\'une approbation du pouvoir.', '', 0),
(6451, 'https://www.radiofrance.fr/franceculture/podcasts/l-actualite-culturelle-reportages-enquetes-analyses', 'L\'Info culturelle : reportages, enquêtes, analyses : podcast et émission en replay | France Culture', 'L\'actualité culturelle vue par la rédaction de France Culture : reportages, enquêtes et analyses sur les arts, les idées et les savoirs. Également sur Instagram, Bluesky, Threads et WhatsApp.', '', 0),
(6452, 'https://www.radiofrance.fr/franceinter/comment-parler-d-amour-en-bande-dessinee-avec-blanche-l-amourante-why-don-t-you-love-me-9638274', 'Comment parler d\'amour en bande dessinée ? Avec \"Blanche\", \"L’Amourante\", \"Why don’t you love me\"... | France Inter', 'Une mère atteinte du sida ; une femme immortelle qui doit sa jeunesse éternelle à l’amour qu’on lui porte ; une mère dépressive qui se demande pourquoi sa famille ne l’aime plus ; une agence pour trouver un amoureux… Quatre BD traversées par la question de l’amour pour les vacances.', '', 0),
(6453, 'https://www.radiofrance.fr/franceinter/podcasts/face-a-l-histoire', 'Face à l\'histoire : podcast et émission en replay | France Inter', 'Philippe Collin propose des séries documentaires historiques, portées par la parole des meilleurs historiens et truffés d’archives rares. Un regard vers le passé pour éclairer notre présent.', '', 0),
(6454, 'https://www.radiofrance.fr/franceculture/podcasts/serie-enqueter-et-ecrire-sur-les-violences-sexuelles', 'Enquêter et écrire sur les violences sexuelles : un podcast à écouter en ligne | France Culture', 'Longtemps considérés comme des faits divers, les affaires de violences sexuelles sont aujourd\'hui reconnues comme un fait de société. Comment le regard journalistique sur elles a-t-il évolué ? Aux côtés d\'Elise Karlin, Lorraine de Foucher, journaliste au Monde, Prix Albert Londres 2024, raconte.', '', 0),
(6455, 'https://www.radiofrance.fr/franceinter/podcasts/philosophes', 'Philosophes : podcast et émission en replay | France Inter', 'Une série de France Inter pour comprendre, découvrir 7 grandes figures, 7 penseurs révolutionnaires dont les idées, les concepts ont changé la manière de voir et de vivre le monde.', '', 0),
(6456, 'https://www.radiofrance.fr/franceinfo/podcasts/les-infox-de-l-histoire', 'Les infox de l\'Histoire : podcast et émission en replay | franceinfo', 'La désinformation n\'est pas un phénomène nouveau. Patrice Gélinet et ses invités analysent les grandes affaires d\'\"infox\" qui ont marqué l\'Histoire. Un podcast Fondation Descartes en partenariat avec franceinfo.', '', 0),
(6457, 'https://www.radiofrance.fr/franceculture/podcasts/serie-la-voix-des-invisibles', 'La Voix des invisibles : un podcast à écouter en ligne | France Culture', 'Dans cette série historique et narrative, l’historien Gérard Noiriel rappelle le rôle essentiel de 20 personnages oubliés ou méconnus, qui ont, à leur manière, été déterminants dans l\'histoire de France – de Brunehaut la reine des Francs à Marthe, paysanne des Hautes-Alpes.', '', 0),
(6458, 'https://www.radiofrance.fr/franceinter/podcasts/serie-masterclass-autour-d-oasis-les-debuts-fulgurants', 'Oasis : les débuts fulgurants : un podcast à écouter en ligne | France Inter', 'Michka Assayas consacre une masterclass au groupe Oasis pour célébrer les 30 ans de leur album mythique \"What\'s the Story Morning Glory\". Entre anecdotes et tubes intemporels, plongez dans  l\'âge d\'or du plus grand groupe anglais des années 90.', '', 0),
(6459, 'https://www.radiofrance.fr/franceinter/podcasts/espions-une-histoire-vraie', 'Podcast Espions, une histoire vraie : des histoires d\'espionnage à écouter sur France Inter', 'AUDIO - Portraits d’espions et d’espionnes, français, américain, anglais, russe, israélien et irakien. De la Seconde Guerre mondiale à aujourd’hui...', '', 0),
(6460, 'https://www.radiofrance.fr/franceculture/podcasts/les-aventuriers-de-l-archeologie', 'Les Aventuriers de l\'archéologie : écouter le podcast et replay | France Culture', 'Grâce à cette nouvelle collection de podcasts, “Les Aventuriers de l’archéologie”, découvrez des épopées scientifiques menées comme des enquêtes. Des découvertes racontées par les archéologues qui les ont faites et qui ont bouleversé la connaissance de notre histoire.', '', 0);
INSERT INTO `sites` (`id`, `url`, `title`, `description`, `keywords`, `clicks`) VALUES
(6461, 'https://www.radiofrance.fr/franceinter/podcasts/serie-capitalisme-une-histoire-de-la-terre', 'Capitalisme, une histoire de la Terre : un podcast à écouter en ligne | France Inter', 'Une série en sept épisodes, qui retrace l\'histoire du capitalisme, ses origines, son développement préindustriel, son influence sur notre rapport à la terre, l\'agriculture, aux ressources naturelles, aux sociétés humaines, en redonnant toute sa place à l\'environnement.', '', 0),
(6462, 'https://www.radiofrance.fr/franceculture/podcasts/serie-comment-trouver-sa-voix-avec-herve-pata', 'Comment trouver sa voix, avec Hervé Pata : un podcast à écouter en ligne | France Culture', 'Pour convaincre son auditoire, les bons mots ne suffisent pas ; encore faut-il les dire avec la voix qui convient. Hervé Pata, professeur en techniques vocales et oratoires, nous apprend à mieux utiliser cet outil essentiel pour s\'exprimer en public et être bien avec soi-même !', '', 0),
(6463, 'https://www.radiofrance.fr/francemusique/podcasts/serie-erik-satie-le-gymnopediste', 'Érik Satie, le Gymnopédiste : un podcast à écouter en ligne | France Musique', 'Érik Satie, enfant mélancolique de Honfleur, grandit entre l’austérité familiale et les récits fantasques d’un oncle iconoclaste. Il rejette l’autorité, le Conservatoire, les règles. Montmartre devient son terrain de jeu : il y improvise au Chat Noir, aime éperdument Suzanne Valadon.', '', 0),
(6464, 'https://www.radiofrance.fr/francebleu/podcasts/partir-des-bons-plans-pour-des-week-ends-en-france-8597288', 'Partir, des bons plans pour des week-ends en France : écouter le podcast et replay | ici', 'Pour voyager et découvrir la France, il y a les bons plans “tourisme” qu’on voit partout dans les guides ou sur les réseaux sociaux et ceux que seuls les gens du coin connaissent. Ecoutez \"Partir\", le podcast \"ici\", pour organiser vos prochains week-ends \"tourisme\" en moins de 15 minutes.', '', 0),
(6465, 'https://www.radiofrance.fr/franceinfo/podcasts/serie-en-route-vers-le-grand-nord', 'En route vers le Grand Nord : un podcast à écouter en ligne | franceinfo', 'Après avoir parcouru le globe avec leur voilier, marins et scientifiques de la fondation Tara vont s\'établir durablement sur la banquise arctique.  Dans cette deuxième saison, découvrez la Tara Polar Station, une vigie scientifique du Grand Nord, à l\'image de la Station Spatiale Internationale.', '', 0),
(6466, 'https://www.radiofrance.fr/franceinter/podcasts/serie-france-algerie-anatomie-d-une-dechirure', 'France-Algérie : anatomie d\'une déchirure : un podcast à écouter en ligne | France Inter', 'Benjamin Stora éclaire l\'histoire complexe et passionnée des relations franco-algériennes, depuis la colonisation jusqu\'à nos jours, en passant par la guerre d\'indépendance, les fractures mémorielles et les héritages qui continuent de façonner le présent.', '', 0),
(6467, 'https://www.radiofrance.fr/franceinter/podcasts/le-7-10', 'Le 7/10 : l\'émission matinale de France Inter en replay et podcast', 'En direct, replay et podcast, écoutez l\'émission matinale de France Inter avec Léa Salamé et Nicolas Demorand. Toutes les infos du jour sont dans le 7/10.', '', 0),
(6468, 'https://www.radiofrance.fr/franceinter/podcasts/affaires-sensibles', 'Affaires sensibles par Fabrice Drouelle sur France Inter', 'PODCAST. Histoires des grandes affaires et procès qui ont marqué notre époque, par Fabrice Drouelle. Écoutez l\'émission en replay sur France Inter.', '', 0),
(6469, 'https://www.radiofrance.fr/franceculture/podcasts/les-pieds-sur-terre', 'Les Pieds sur terre : podcast de reportages sur France Culture', 'PODCAST. Chaque jour, une demi-heure de reportage sans commentaire. Écoutez en replay l\'émission Les Pieds sur terre par Sonia Kronlund sur France Culture.', '', 0),
(6470, 'https://www.radiofrance.fr/franceculture/podcasts/les-matins', 'Les Matins d\'été : podcast et émission en replay | France Culture', 'Chaque matin, pour une lecture quotidienne du monde et de la culture : une info riche et diversifiée, des éditoriaux, des chroniques, une revue de presse et des invités acteurs des mondes intellectuels, sociaux et culturels.', '', 0),
(6471, 'https://www.radiofrance.fr/franceinter/podcasts/la-bande-originale', 'La Bande originale avec Nagui sur France Inter', 'PODCAST. Chaque jour avec Nagui, de la bonne humeur et de l’impertinence pour une émission drôle et joyeuse ! Émission en replay sur France Inter.', '', 0),
(6472, 'https://www.radiofrance.fr/franceinter/podcasts/zoom-zoom-zen', 'Zoom zoom zen : podcast et émission en replay | France Inter', 'Aujourd’hui, nous sommes submergés d’infos, néanmoins nous prenons rarement le temps d’aller au-delà des gros titres. Nous connaissons tout… mais en surface. Et si chaque jour, nous zoomions sur un mot nouveau pour vraiment le comprendre ?', '', 0),
(6473, 'https://www.radiofrance.fr/franceculture/podcasts/le-cours-de-l-histoire', 'Le Cours de l\'histoire en replay et podcast sur France Culture', 'PODCAST. Écoutez en ligne Le Cours de l\'histoire par Xavier Mauduit sur France Culture. Chaque jour, un récit pour mieux comprendre le temps présent.', '', 0),
(6474, 'https://www.radiofrance.fr/franceinter/podcasts/grand-bien-vous-fasse', 'Grand bien vous fasse ! Écouter en replay et podcast sur France Inter', 'PODCAST. Le rendez-vous d\'Ali Rebeihi qui aborde vos préoccupations de la vie quotidienne. Écoutez l\'émission en replay sur France Inter.', '', 0),
(6475, 'https://www.radiofrance.fr/franceinter/podcasts/geopolitique', 'Géopolitique par Pierre Haski en podcast sur France Inter', 'PODCAST. Écoutez en replay l\'émission Géopolitique de Pierre Haski : analyses et explications de l\'actualité internationale, relations diplomatiques.', '', 0),
(6476, 'https://www.radiofrance.fr/franceculture/podcasts/lsd-la-serie-documentaire', 'LSD, la série documentaire en podcast sur France Culture', 'PODCAST. L\'émission LSD, la série documentaire, vise à documenter les expériences, les cultures et les savoirs. Écoutez en ligne sur France Culture.', '', 0),
(6477, 'https://www.radiofrance.fr/franceculture/podcasts/fictions-le-feuilleton', 'Le Feuilleton : podcast et émission en replay | France Culture', 'Un rendez-vous destiné au grand public. Ces fictions auront pour mission de nous émouvoir, nous divertir, nous intriguer. Dramatiques radiophoniques, lectures, scénarios, adaptations, pages arrachées, toutes les formes radiophoniques et toutes les époques sont conviées pour conter une histoire.', '', 0),
(6478, 'https://www.radiofrance.fr/franceculture/podcasts/les-nuits-de-france-culture', 'Les Nuits de France Culture : écouter en replay et podcast', 'PODCAST. En direct et replay, retrouvez l\'émission Les Nuits de France Culture. Écoutez en ligne une sélection des meilleures archives de la radio.', '', 0),
(6479, 'https://www.radiofrance.fr/franceinter/podcasts/la-terre-au-carre', 'La Terre au carré par Mathieu Vidard sur France Inter', 'PODCAST. Toute l\'actualité de la planète pour imaginer le monde de demain, avec Mathieu Vidard. Écoutez l\'émission en replay sur France Inter.', '', 0),
(6480, 'https://www.radiofrance.fr/franceinter/podcasts/le-masque-et-la-plume', 'Le Masque et la plume par Rebecca Manzoni sur France Inter', 'PODCAST. Écoutez en replay Le Masque et la plume sur France Inter. Autour de Jérôme Garcin, revues et critiques des dernières productions culturelles.', '', 0),
(6481, 'https://www.radiofrance.fr/franceculture/podcasts/cultures-monde', 'Cultures Monde : émission en replay et podcast sur France Culture', 'PODCAST. En replay, écoutez l\'émission Cultures Monde sur France Culture. Enjeux contemporains de la mondialisation selon les pays du monde.', '', 0),
(6482, 'https://www.radiofrance.fr/sciences-savoirs/sciences', 'Sciences : Toute l\'actualité et les podcasts scientifiques à écouter | Radio France', 'Écoutez les derniers podcasts et suivez l\'actualité scientifique avec Radio France. Toute la science en séries audio, dossiers et émissions en replay.', '', 0),
(6483, 'https://www.radiofrance.fr/vie-quotidienne/cuisine', 'Cuisine : Tous les podcasts et l\'actualité des passionnés de cuisine | Radio France', 'Écoutez les podcasts et retrouvez toute l\'actualité autour de la passion de la cuisine. Avec des recettes uniques, des idées pour égayer vos papilles.', '', 0),
(6484, 'https://www.radiofrance.fr/arts-divertissements/livres', 'Livres & Littérature : Toute l\'actualité littéraire en podcast | Radio France', 'Écoutez les derniers podcasts de Radio France sur la thématique Livres & Littérature : actualités, critiques de livres, idées et conseils de lectures.', '', 0),
(6485, 'https://www.radiofrance.fr/arts-divertissements/humour', 'Humour : Tous les podcasts, sketches et chroniques des humoristes | Radio France', 'Écoutez les derniers sketches et podcasts humoristiques des antennes de Radio France. Les humoristes proposent des contenus inédits. Abonnez-vous !', '', 0),
(6486, 'https://www.radiofrance.fr/franceculture/podcasts/serie-cent-ans-de-frantz-fanon-panser-les-plaies-coloniales', 'Cent ans de Frantz Fanon : panser les plaies coloniales : un podcast à écouter en ligne | France Culture', 'En 2025, Frantz Fanon aurait eu 100 ans. L\'occasion de revenir sur la pensée d\'un psychiatre révolutionnaire qui aura lutté toute sa vie contre la domination et les violences coloniales.', '', 0),
(6487, 'https://www.radiofrance.fr/franceinter/podcasts/serie-les-textes-illustres-du-moyen-age', 'Les textes illustres du Moyen Âge : un podcast à écouter en ligne | France Inter', 'Découvrez les textes qui ont façonné l\'imaginaire du Moyen Âge. De la chanson de Roland au conte du Graal, des animaux symboliques à la satire de Renart, Michel Pastoureau analyse l\'héritage de la littérature médiévale, entre histoire et légendes', '', 0),
(6488, 'https://www.radiofrance.fr/franceculture/podcasts/serie-l-instant-poesie-vers-le-zen', 'L’Instant poésie : vers le zen : un podcast à écouter en ligne | France Culture', '\"L’Instant poésie\" invite à la contemplation avec dix poèmes choisis pour leur pouvoir apaisant. Une bulle hors du tumulte, où les mots dessinent des paysages intérieurs et suspendent le temps, pour savourer la beauté de l’instant et la puissance évocatrice du langage.', '', 0),
(6489, 'https://www.radiofrance.fr/franceinter/podcasts/serie-les-ottomans-et-leur-empire', 'Les Ottomans et leur empire  : un podcast à écouter en ligne | France Inter', 'Sultans, janissaires, Sublime Porte, Tanzimat... L\'histoire de l\'Empire ottoman, depuis sa grandeur multiculturelle à sa chute. Aux sources d\'une puissance millénaire et de son héritage complexe qui façonne encore la Turquie moderne.', '', 0),
(6490, 'https://www.radiofrance.fr/franceculture/podcasts/serie-qu-est-ce-qui-pourrait-sauver-l-amour-ovidie', 'Qu’est-ce qui pourrait sauver l’amour ? : un podcast à écouter en ligne | France Culture', 'Pour LSD, Ovidie, épaulée par son acolyte Tancrède Ramonet, se lance dans une tentative de définition pluridisciplinaire afin de déconstruire toute cette culture aliénante de l’amour dans l’espoir de mieux la réinventer. Mais qu’est-ce qui pourrait sauver l’amour ? Réalisation : Julie Beressi.', '', 0),
(6491, 'https://www.radiofrance.fr/franceinter/podcasts/serie-les-vacances-racontent-la-france', 'Les vacances racontent la France  : un podcast à écouter en ligne | France Inter', 'En route pour un voyage historique et ensoleillé : découvrez comment les vacances des français ont évolué au fil des siècles : des bancs de l\'école aux bancs de sables bondés, entre impératifs économiques, aspirations pédagogiques et recherche de loisirs.', '', 0),
(6492, 'https://www.radiofrance.fr/francemusique/podcasts/le-jazz-en-france-sous-l-occupation', 'Le jazz en France sous l\'Occupation : écouter le podcast et replay | France Musique', 'Les difficiles années de l’Occupation ont aussi été une période faste pour le jazz en France. Pourtant contraire aux valeurs prônées par le national-socialisme, cette musique ne fut jamais interdite par les Nazis.', '', 0),
(6493, 'https://www.radiofrance.fr/franceculture/podcasts/serie-les-maitres-du-roman-populaire-francais', 'Les maîtres du roman populaire français : un podcast à écouter en ligne | France Culture', 'Dans cette série sur les maîtres du roman populaire, Pierre Dupriez et Serge Martel explorent un genre certes dédaigné mais qui connut un véritable succès. Qu\'ils soient policiers, d\'aventure, de cape et d\'épée, de mœurs ou fantastiques, ces romans sont le reflet d\'une société en pleine évolution.', '', 0),
(6494, 'https://www.radiofrance.fr/franceinter/podcasts/serie-best-of-benjamin-tranie', 'Best of Benjamin Tranié : une sélection des meilleurs podcasts à écouter | France Inter', 'AUDIO. Découvrez cette sélection des meilleurs podcasts à écouter gratuitement. Best of Benjamin Tranié : chroniques, podcasts et émissions de radio du moment, ce qu\'il ne fallait pas manquer, extraits de l\'actualité et des archives de Radio France.', '', 0),
(6495, 'https://www.radiofrance.fr/franceculture/podcasts/serie-les-liens-du-coeur', 'Les liens du cœur  : un podcast à écouter en ligne | France Culture', 'Coup de foudre, amour à distance, retrouvé, brisé ou disparu sans explication… l\'amour semble ne pas avoir de logique. Des récits qui explorent le sentiment amoureux et ce qu\'il nous pousse à faire.', '', 0),
(6496, 'https://www.radiofrance.fr/franceinter/podcasts/serie-crimes-et-manigances-au-siecle-des-lumieres', 'Crimes et manigances au siècle des Lumières   : un podcast à écouter en ligne | France Inter', 'La bête du Gévaudan, l’assassinat de Marat, la tentative de régicide de Robert-François Damiens, l’affaire Callas, la nuit du 4 août 1789… Le XVIIIe siècle est émaillé de crimes révélateurs de l’époque pré-révolutionnaire.', '', 0),
(6497, 'https://www.radiofrance.fr/franceculture/podcasts/serie-l-idee-de-voyage', 'L\'idée de voyage : un podcast à écouter en ligne | France Culture', 'Il existe différentes manières de voyager. Il y a ces voyages que nous faisons grâce à l\'imagination. Il y a aussi ceux que nous faisons dans l\'optique d\'une réelle rencontre avec autrui, avec le risque d\'exotisation ou d\'aveuglement idéologique. Voyager authentiquement, est-ce vraiment possible ?', '', 0),
(6498, 'https://www.radiofrance.fr/franceinter/podcasts/serie-alfred-dreyfus-le-combat-de-la-republique', 'Alfred Dreyfus, le combat de la République : un podcast à écouter en ligne | France Inter', 'Voici l\'histoire d\'une machination judiciaire, d\'une cicatrice. L\'affaire Dreyfus, une querelle française qui s\'estompe dans les mémoires. Et pourtant, c\'est une balafre autour de laquelle s\'est redessinée la société française du XXᵉ siècle.', '', 0),
(6499, 'https://www.radiofrance.fr/franceinter/les-millennials-commencent-leur-crise-de-la-quarantaine-a-quoi-s-attendre-8825778', 'Les millennials commencent leur crise de la quarantaine, à quoi s\'attendre ? | France Inter', 'La crise de la quarantaine est-elle en crise ? L\'image de l\'homme qui change de voiture a fait son temps. Le milieu de vie n\'est plus tout à fait le même qu\'auparavant et l\'on exprime plus ses doutes et renoncements de la même manière.', '', 0),
(6500, 'https://www.radiofrance.fr/franceinter/podcasts/une-histoire-et-oli', 'Une histoire et Oli, histoires pour enfants avant d’aller dormir | France Inter', 'Vous cherchez des histoires du soir pour vos enfants ? Découvrez les nouveaux épisodes d\'Une histoire et Oli, la série audio France Inter pour les 5-7 ans.', '', 0),
(6501, 'https://www.radiofrance.fr/franceinter/podcasts/serie-les-grands-maitres-du-mystere', 'Les grands maîtres du mystère : un podcast à écouter en ligne | France Inter', 'Laure Grandbesançon a kidnappé les maîtres du mystère : Sherlock Holmes, Arsène Lupin, Hercule Poirot et Rouletabille.', '', 0),
(6502, 'https://www.radiofrance.fr/franceinter/podcasts/serie-les-p-tits-bateaux-pop', 'Les p’tits bateaux pop : un podcast à écouter en ligne | France Inter', 'Musique, cinéma, séries... dans les P\'tits Bateaux, il est souvent question de pop culture ! On y apprend des informations insolites, de quoi voir nos œuvres préférées avec un autre œil.', '', 0),
(6503, 'https://www.radiofrance.fr/franceinter/podcasts/toudou', 'Toudou : le podcast pour les enfants tout petits et leurs parents par France Inter', 'Un podcast 2 en 1 pour les tout-petits et leurs parents ! Une face A : une histoire pour les enfants de 2 à 4 ans avec Toudou le doudou tout mou, tout chou, tout fou ! Une face B : une notice pour comprendre ce que Toudou éveille dans le cerveau des enfants.', '', 0),
(6504, 'https://www.radiofrance.fr/francemusique/podcasts/serie-le-voyage-d-ulysse', 'Le voyage d\'Ulysse : un podcast à écouter en ligne | France Musique', 'Dès 5 ans. Qui n\'a jamais rêvé de vivre l\'aventure avec Ulysse, héros grec aux nombreuses ruses ! Après la guerre de Troie, Ulysse, roi d\'Ithaque, n\'a qu\'une hâte : retrouver sa femme Pénélope et son fils Télémaque. Malheureusement, il traversera bien des tempêtes et son voyage durera 10 ans.', '', 0),
(6505, 'https://www.radiofrance.fr/franceinter/podcasts/bestioles', 'Bestioles : histoires d\'animaux pour enfants en podcasts – France Inter', 'PODCAST. Écoutez la série audio Bestioles, un podcast éducatif et ludique pour les enfants de 5-7 ans. À chaque épisode, découvrons un nouvel animal.', '', 0),
(6506, 'https://www.radiofrance.fr/francemusique/podcasts/serie-le-sport', 'Le sport : un podcast à écouter en ligne | France Musique', 'Octave et Mélo ne sont pas que musiciens. Ils sont aussi sportifs et aiment tester différentes activités comme le foot, l\'équitation, la danse ou le ski. Suis-les dans leurs aventures !', '', 0),
(6507, 'https://www.radiofrance.fr/franceinter/podcasts/les-explorateurs-de-l-univers', 'Les explorateurs de l\'Univers : podcast et émission en replay | France Inter', 'Pour la première fois depuis que l’Univers existe, un humain nous parle depuis l’autre bout du cosmos. Aidan souhaite former les enfants de la Terre au savoir d’aujourd\'hui, les faire voyager dans l’espace et le temps, leur faire découvrir pourquoi les étoiles brillent, survoler les autres mondes !', '', 0),
(6508, 'https://www.radiofrance.fr/franceinter/podcasts/les-aventures-du-professeur-caillou', 'Les aventures du professeur Caillou : podcast et émission en replay | France Inter', 'Les aventures de deux géologues pour découvrir le rôle des métaux dans notre quotidien, leurs origines géologiques et certains enjeux associés à leur production et leur recyclage.', '', 0),
(6509, 'https://www.radiofrance.fr/fip/podcasts/la-discomobile', 'La Discomobile : podcast et émission en replay | FIP', 'Les légendes de la musique racontées à vos enfants. Le premier podcast de FIP pour les 7 ans et plus, animé par Émilie Blon-Metzinger et réalisé par Alexandre Girard.', '', 0),
(6510, 'https://www.radiofrance.fr/franceinter/podcasts/les-odyssees', 'Les Odyssées : un podcast pour enfants par France Inter', 'PODCAST. Plongez-vous dans les aventures des grandes figures de l\'histoire ! 80 épisodes à écouter en famille, avec vos enfants de 7 à 12 ans.', '', 0),
(6511, 'https://www.radiofrance.fr/franceinter/podcasts/serie-les-bestioles-sous-l-ocean', 'Les bestioles sous l\'océan : un podcast à écouter en ligne | France Inter', 'De la méduse au requin, en passant par la baleine et le poisson-clown, partez à la découverte des bestioles sous l’océan !', '', 0),
(6512, 'https://www.radiofrance.fr/franceculture/podcasts/serie-les-malheurs-de-sophie-une-comedie-musicale-de-sabine-zovighian-et-michael-liot', '\"Les Malheurs de Sophie, une comédie musicale\" de Sabine Zovighian et Michael Liot : un podcast à écouter en ligne | France Culture', 'Sophie n’est pas une petite fille modèle. C’est plus fort qu’elle : de drôles d’envies traversent tout le temps son esprit et la poussent à faire bêtise sur bêtise. Est-ce qu’elle le fait exprès ? C’est une question difficile.', '', 0),
(6513, 'https://www.radiofrance.fr/franceinter/podcasts/serie-les-p-tits-crados', 'Les P\'tits Crados : un podcast à écouter en ligne | France Inter', 'Caca, prouts, vomi, crottes de nez… Les enfants se posent beaucoup de questions rafraîchissantes ! Les experts des P\'tits Bateaux leur répondent sans se boucher le nez.', '', 0),
(6514, 'https://www.radiofrance.fr/franceinter/podcasts/serie-tina-et-la-ceinture-d-alexandre-le-grand', 'Tina et la ceinture d\'Alexandre le Grand : un podcast à écouter en ligne | France Inter', 'La suite des aventures de Tina. Après l\'Egypte et le trésor de Nefertiti, la voici lancée sur les traces de la ceinture d\'Alexandre le Grand. Toujours accompagnée de son fidèle ami Mouss.', '', 0),
(6515, 'https://www.radiofrance.fr/franceinter/podcasts/l-info-de-france-inter/l-info-de-france-inter-21-juillet-2025-1-8536661', 'Pétition contre la loi Duplomb : face à la mobilisation, les défenseurs du texte contre-attaquent | France Inter', 'La pétition contre la loi Duplomb ne cesse d\'enregistrer de nouvelles signatures, dépassant désormais le million. La gauche promet de tout faire pour rediscuter du texte à l\'automne. Les défenseurs de la loi se mobilisent ce lundi pour tenter d\'éteindre l\'incendie.', '', 0),
(6516, 'https://www.radiofrance.fr/franceinter/podcasts/l-invite-de-7h50/l-invite-de-7h50-du-lundi-21-juillet-2025-4437744', 'Constance Dewavrin, avocate pénaliste : \"On voit, on entend des choses lourdes et il faut un canal d\'évacuation\" | France Inter', 'L\'avocate pénaliste Constance Dewavrin, spécialiste de l’accompagnement des victimes et co-fondatrice du cabinet NOVO-avocats, était l\'invitée de France Inter ce lundi.', '', 0),
(6517, 'https://www.radiofrance.fr/franceinter/podcasts/l-invite-de-7h50', 'L\'invité de 7h50 : podcast et émission en replay | France Inter', 'Il ou elle fait l\'actualité ; un entretien sans concession pour décrypter le fait politique, culturel ou économique du jour.', '', 0),
(6518, 'https://www.radiofrance.fr/franceinter/podcasts/l-heure-du-rap/l-heure-du-rap-avec-shay-du-samedi-19-juillet-2025-4028120', 'Shay, une rappeuse aux sommets, confiante et effrontée avec \"Pourvu qu\'il pleuve\" | France Inter', '2024, les rappeuses sont encore peu nombreuses en têtes d\'affiches. L\'une d\'entre elles, Shay, va s\'imposer et dépasser nombre de représentants d\'un milieu alors très majoritairement masculin. C\'est l\'année de son album \"Pourvu qu\'il pleuve\".', '', 0),
(6519, 'https://www.radiofrance.fr/franceinter/podcasts/l-heure-du-rap', 'L\'heure du rap : écouter le podcast et replay | France Inter', 'Chaque weekend, Mehdi Maïzi dresse le portrait d’une figure majeure du rap. À travers un album emblématique, il retrace leur parcours, leur succès, et explore ce qui fait d’eux des artistes incontournables.', '', 0),
(6520, 'https://www.radiofrance.fr/franceinter/podcasts/le-masque-et-la-plume/le-masque-et-la-plume-du-dimanche-20-juillet-2025-5973788', 'Avignon (2) : \"La Distance\", \"Annette\", \"La lettre\", \"Les Paillettes de leur vie\", \"Les Perses\" | France Inter', 'Un père et sa fille dans \"La Distance\" de Tiago Rodrigues ; une mère qui n’a pas envie de l’être dans \"Annette\" de Clémentine Colpin ; des comédiens et leur grand-mère dans \"La lettre\" de Milo Rau ; un quadragénaire qui veut faire un don de sperme dans \"Les Paillettes de leur vie\" de Mickaël Délis…', '', 0),
(6521, 'https://www.radiofrance.fr/franceinter/podcasts/les-p-tits-bateaux/les-p-tits-bateaux-du-dimanche-03-novembre-2024-4892457', 'Quand on est dans l’espace et qu’un astronaute est très très malade, comment on fait ? | France Inter', 'Aujourd\'hui, Lise, qui va bientôt avoir 9 ans, se demande comment on fait  quand dans l\'espace un astronaute est très très malade. Thomas Pesquet lui répond.', '', 0),
(6522, 'https://www.radiofrance.fr/franceinter/podcasts/les-p-tits-bateaux', 'Les P\'tits Bateaux : podcast et émission en replay | France Inter', 'Les enfants posent des questions, des spécialistes leur répondent. Jeunes (et moins jeunes !) peuvent poser toutes les questions possibles et imaginables directement par message vocal via franceinter.fr, sauf pendant les vacances.', '', 0),
(6523, 'https://www.radiofrance.fr/franceculture/podcasts/lsd-la-serie-documentaire/les-mines-une-histoire-du-paternalisme-5306611', 'Les mines, une histoire du paternalisme  : épisode 1/4 du podcast Au fond de la mine | France Culture', 'AUDIO • Au fond de la mine, épisode 1/4 : Les mines, une histoire du paternalisme . Une série inédite proposée par France Culture. Écoutez LSD, la série documentaire, et découvrez nos podcasts en ligne.', '', 0),
(6524, 'https://www.radiofrance.fr/franceculture/podcasts/le-book-club/dans-la-bibliotheque-de-sonia-wieder-atherton-8531637', 'Dans la bibliothèque de Sonia Wieder-Atherton : épisode  du podcast Dans la bibliothèque de... | France Culture', 'AUDIO • Dans la bibliothèque de..., épisode  : Dans la bibliothèque de Sonia Wieder-Atherton. Une série inédite proposée par France Culture. Écoutez Le Book Club, et découvrez nos podcasts en ligne.', '', 0),
(6525, 'https://www.radiofrance.fr/franceculture/podcasts/bienvenue-au-book-club-part-2', 'Le Book Club : podcast et émission en replay | France Culture', 'Place aux livres ! Dans ce club de lecture participatif, écrivains et lecteurs de tout horizon partagent leurs plaisirs de lecture et d\'écriture, à l’antenne et sur les réseaux sociaux.\r\nÀ suivre sur Instagram 👉🏼 #bookclubculture', '', 0),
(6526, 'https://www.radiofrance.fr/franceculture/podcasts/les-pieds-sur-terre/les-pieds-sur-terre-du-jeudi-20-mai-2021-6846416', 'Chip Chan, la prisonnière du web : épisode 1/6 du podcast Histoires 2.0 | France Culture', 'AUDIO • Histoires 2.0, épisode 1/6 : Chip Chan, la prisonnière du web. Une série inédite proposée par France Culture. Écoutez Les Pieds sur terre, et découvrez nos podcasts en ligne.', '', 0),
(6527, 'https://www.radiofrance.fr/franceculture/podcasts/avoir-raison-avec/l-homme-face-a-la-nature-1545100', 'L\'Homme face à la nature : épisode 1/5 du podcast Avoir raison avec... Jean Giono | France Culture', 'AUDIO • Avoir raison avec... Jean Giono, épisode 1/5 : L\'Homme face à la nature. Une série inédite proposée par France Culture. Écoutez Avoir raison avec...  , et découvrez nos podcasts en ligne.', '', 0),
(6528, 'https://www.radiofrance.fr/franceculture/podcasts/avoir-raison-avec', 'Avoir raison avec...   : podcast et émission en replay | France Culture', 'Du lundi au vendredi, une grande voix de France Culture reprend une figure de la pensée moderne qui nous aide à comprendre ce qui se passe, par delà les disciplines.', '', 0),
(6529, 'https://www.radiofrance.fr/franceculture/podcasts/ils-ont-change-le-monde/les-accords-de-schengen-dans-la-tempete-7016490', 'Les Accords de Schengen dans la tempête : épisode  du podcast Les accords qui ont changé le monde | France Culture', 'AUDIO • Les accords qui ont changé le monde , épisode  : Les Accords de Schengen dans la tempête. Une série inédite proposée par France Culture. Écoutez Ils ont changé le monde, et découvrez nos podcasts en ligne.', '', 0),
(6530, 'https://www.radiofrance.fr/franceculture/podcasts/la-culture-change-le-monde', 'Ils ont changé le monde : podcast et émission en replay | France Culture', 'La collection \"Ils ont changé le monde\" décrypte de grands événements et objets culturels qui ont marqué l’histoire.', '', 0),
(6531, 'https://www.radiofrance.fr/franceculture/podcasts/les-grandes-traversees/episode-1-5-une-enfance-hors-norme-4308011', 'Une enfance hors norme : épisode 1/5 du podcast Hildegarde de Bingen, génie cosmique | France Culture', 'AUDIO • Hildegarde de Bingen, génie cosmique, épisode 1/5 : Une enfance hors norme. Une série inédite proposée par France Culture. Écoutez Les Grandes Traversées , et découvrez nos podcasts en ligne.', '', 0),
(6532, 'https://www.radiofrance.fr/franceculture/podcasts/grandes-traversees', 'Les Grandes Traversées  : podcast et émission en replay | France Culture', 'Depuis 2006, France Culture propose chaque année des Grandes Traversées, épopées radiophoniques qui rassemblent documentaires, archives et débats. Chacune est consacrée à une figure qui a marqué et marque encore l\'histoire.', '', 0),
(6533, 'https://www.radiofrance.fr/newsletters-preview/radiofrance/newsletter/index.html', 'Radio France - Preview - Bonnes ondes | La newsletter qui dort sur ses deux oreilles', '', '', 0),
(6534, 'https://www.radiofrance.fr/francemusique/podcasts/le-concert-de-l-apres-midi/correspondances-et-sebastien-dauce-au-service-de-sa-majeste-5615626', 'Correspondances et Sébastien Daucé au service de Sa Majesté | France Musique', 'Aux créations de Robert et Du Mont pour Louis XIV, répondent les pages de Humphrey, Blow et Purcell, à la cour de Charles II d’Angleterre. Sébastien Daucé et l’Ensemble Correspondances en sont les remarquables interprètes, à l’Auditorium du Louvre.', '', 0),
(6535, 'https://www.radiofrance.fr/francemusique/podcasts/le-concert-de-l-apres-midi', 'Le concert de l\'après-midi : podcast et émission en replay | France Musique', 'Tous les après-midi d’été, plongeons dans le meilleur des concerts captés partout en France, à l’Auditorium de la Maison de la radio et de la musique, dans les salles de concert aux quatre coins de l’hexagone : symphonique, musique de chambre, baroque, piano... il y en aura pour tous les goûts !', '', 0),
(6536, 'https://www.radiofrance.fr/francemusique/podcasts/stars-du-classique/artur-rodzinski-un-tres-grand-chef-au-caractere-imperieux-6709484', 'Artur Rodziński, un très grand chef au caractère impérieux | France Musique', 'Sa carrière débutée à Varsovie, Artur Rodziński rejoint les USA où il est assistant de Leopold Stokowksi à Philadelphie de 1926 à 1929. Puis il mène à un très haut niveau musical les grandes formations de Los Angeles, New York, Chicago et Cleveland.', '', 0),
(6537, 'https://www.radiofrance.fr/francemusique/podcasts/stars-du-classique', 'Stars du classique : podcast et émission en replay | France Musique', 'Solistes, chefs, chanteurs… Chaque jour, portrait d’un grand nom de la musique classique, des nouvelles stars aux artistes de légende.', '', 0),
(6538, 'https://www.radiofrance.fr/francemusique/podcasts/les-sagas-musicales/episode-1-l-enfant-5491868', 'L’enfant : épisode 1/5 du podcast Pierre Boulez, une vie sur le ring | France Musique', 'AUDIO • Pierre Boulez, une vie sur le ring, épisode 1/5 : L’enfant. Une série inédite proposée par France Musique. Écoutez Les Sagas musicales, et découvrez nos podcasts en ligne.', '', 0),
(6539, 'https://www.radiofrance.fr/francemusique/podcasts/les-sagas-musicales', 'Les Sagas musicales : podcast et émission en replay | France Musique', 'Figures de légende, compositrices, compositeurs de génie, grands noms de l\'histoire de la musique, lieux de création... Pour plonger dans la biographie d’un artiste, une saga musicale en 5 épisodes à découvrir grâce à Saskia De Ville ou en version long format par les producteurs de France Musique.', '', 0),
(6540, 'https://www.radiofrance.fr/francemusique/podcasts/un-instrument-une-vie/karl-leister-la-clarinette-de-karajan-5621966', 'Karl Leister : la clarinette de Karajan : épisode 5/11 du podcast Les légendes de la clarinette | France Musique', 'AUDIO • Les légendes de la clarinette, épisode 5/11 : Karl Leister : la clarinette de Karajan. Une série inédite proposée par France Musique. Écoutez Un instrument, une vie, et découvrez nos podcasts en ligne.', '', 0),
(6541, 'https://www.radiofrance.fr/francemusique/podcasts/un-instrument-une-vie', 'Un instrument, une vie : écouter le podcast et replay | France Musique', 'Dans la collection \"Un instrument, une vie\", découvrez la vie de musiciens et musiciennes de légende racontée par des musiciens d\'aujourd\'hui. Christian-Pierre La Marca pour le violoncelle, Sébastien Llinarès pour la guitare ou encore Nicolas Baldeyrou pour la clarinette.', '', 0),
(6542, 'https://www.radiofrance.fr/fip/podcasts/fip-tape/la-mixtape-de-sade-adu-6112348', 'La mixtape de Sade | FIP', 'Pour célébrer les quarante ans de son premier album \"Diamond Life\", Fip Tape vous invite dans l\'univers de la chanteuse britannique entre inspirations, anecdotes, collaborations et héritage.', '', 0),
(6543, 'https://www.radiofrance.fr/fip/podcasts/fip-tape', 'Fip Tape : podcast et émission en replay | FIP', 'Mieux qu\'une playlist, des voyages musicaux sur mesure conçus par l\'équipe de programmation de Fip, ré-écoutable à l\'infini !', '', 0),
(6544, 'https://www.radiofrance.fr/fip/podcasts/club-jazzafip/special-montreux-jazz-festival-avec-ganavya-et-alfredo-rodriguez-6054214', 'Spécial Montreux Jazz Festival avec Ganavya, Alfredo Rodriguez et DJ Spinna | FIP', 'Pour cette 59e édition du festival suisse, nous invitons la chanteuse américano-indienne Ganavya, le pianiste cubain Alfredo Rodriguez et le DJ-producteur new-yorkais.', '', 0),
(6545, 'https://www.radiofrance.fr/fip/podcasts/club-jazzafip', 'Club Jazzafip  : podcast et émission en replay | FIP', 'Un rendez-vous dans lequel s’entremêlent tous les jazz, incarné par du lundi au jeudi par Marjolaine Portier-Kaltenbach. Chaque soir, un programmateur ou un invité sont au micro pour naviguer des grands standards aux artistes émergents.', '', 0),
(6546, 'https://www.radiofrance.fr/fip/podcasts/club-jazzafip/special-montreux-jazz-festival-avec-hermanos-gutierrez-8223558', 'Spécial Montreux Jazz Festival avec Hermanos Gutiérrez | FIP', 'Entre deux extraits des meilleurs concerts de la 59e édition du festival suisse, nous invitons les deux frères guitaristes Alejandro et Estevan Gutiérrez qui présentent à Montreux les paysages sonores hypnotiques de leur deuxième album \"Sonido Cósmico\".', '', 0),
(6547, 'https://www.radiofrance.fr/fip/le-kronos-quartet-reprend-a-hard-rain-s-a-gonna-fall-de-bob-dylan-5435310', 'Le Kronos Quartet reprend \"A Hard Rain’s A‐Gonna Fall\" de Bob Dylan | FIP', 'Pour les 80 ans ans de la naissance de la bombe nucléaire, le quatuor présente deux reprises de la chanson pacifiste, enregistrées avec Iggy Pop, Willie Nelson, Allison Russell, Ringo Starr, Sampa the Great, Tom Morello, Charlotte Gainsbourg et d\'autres.', '', 0),
(6548, 'https://www.radiofrance.fr/musique/rock/folk', 'Folk : Tous les podcasts, actualités et playlists musique Folk | Radio France', 'Toute l\'actualité Folk sur Radio France. Podcasts à écouter gratuitement en ligne et depuis l\'application, avec les dernières actualités et débats.', '', 0),
(6549, 'https://www.radiofrance.fr/savoirs-plus', 'Education, savoirs, des podcasts à écouter | Radio France', 'Histoire de l’art, sciences cognitives, astrophysique… les savoirs les plus pointus sont réunis au service de l’intelligence. Découvrez une collection unique de cours et de conférences des meilleures institutions de recherche et de culture : Collège de France, Sciences Po, et bien d’autres à venir.', '', 0),
(6550, 'https://www.radiofrance.fr/francebleu/podcasts/2-minutes-pour-etre-en-forme/le-gainage-l-exercice-cle-pour-renforcer-votre-posture-et-votre-corps-9198007', 'Le gainage : l’exercice clé pour renforcer votre posture et votre corps | ici', 'Découvrez avec Nordine Attab, coach sportif, un exercice simple mais redouté : le gainage. Facile à intégrer à votre routine, il vous aide à améliorer votre posture et à renforcer vos muscles profonds, même si vous êtes débutant.', '', 0),
(6551, 'https://www.radiofrance.fr/francebleu/podcasts/2-minutes-pour-etre-en-forme-3482760', '2 minutes pour être en forme : podcast et émission en replay | ici', 'Chaque jour, le coach sportif Nordine Attab vous donne une idée d’exercice, facile à mettre en œuvre, avec les moyens du bord et selon votre niveau.  En 2 minutes et de manière ludique, ICI vous offre une boite à outils pour vous sentir mieux dans votre corps.', '', 0),
(6552, 'https://www.radiofrance.fr/francebleu/podcasts/comment-occuper-les-enfants/un-cerf-volant-a-fabriquer-soi-meme-l-astuce-facile-pour-des-heures-de-jeu-en-plein-air-4577045', 'Un cerf-volant à fabriquer soi-même : l’astuce facile pour des heures de jeu en plein air | ici', 'Avec quelques pailles, du fil et un sac plastique, fabriquez un cerf-volant maison pour amuser vos enfants. Une activité DIY facile et ludique pour profiter du grand air sans dépenser un centime.', '', 0),
(6553, 'https://www.radiofrance.fr/francebleu/podcasts/ma-france-7077782', 'Ma France, le journal des régions : podcast et émission en replay | ici', 'Ma France, le magazine d\'actualité des 44 radio locales \"ici\" présenté par Emeline Ferry dès 13h !', '', 0),
(6554, 'https://www.radiofrance.fr/francebleu/podcasts/c-est-pas-vrai/une-promesse-d-emploi-facile-et-bien-paye-attention-a-ces-sms-dangereux-5769834', 'Une promesse d\'emploi facile et bien payé ? Attention à ces SMS dangereux | ici', 'On vous alerte ce matin sur une vague de SMS frauduleux', '', 0),
(6555, 'https://www.radiofrance.fr/francebleu/podcasts/c-est-pas-vrai-1441199', 'C\'est pas vrai ?! : podcast et émission en replay | ici', 'Puisque les fake news et infox sont devenues malheureusement incontournables, votre radio \"ici\" vous propose de démêler le vrai du faux avec Aude Raso et Valentine Letesse.', '', 0),
(6556, 'https://www.radiofrance.fr/franceculture/podcasts/journal-de-8-h/journal-de-8h-du-lundi-21-juillet-2025-7408284', 'Plus d\'un million de signatures pour la pétition contre la loi Duplomb | France Culture', 'La mobilisation continue contre la loi agricole Duplomb, malgré l\'adoption du texte. La pétition contre le texte déjà adopté mais pas encore promulgué a dépassé le million de signatures. Les députés qui ont voté pour sont interpellés sur internet et se justifient.', '', 0),
(6557, 'https://www.radiofrance.fr/franceinfo/podcasts/l-edito-politique/edito-succes-inedit-pour-la-petition-contre-la-loi-duplomb-qui-est-le-plus-legitime-les-petitionnaires-ou-les-parlementaires-9349779', 'EDITO. Succès inédit pour la pétition contre la loi Duplomb : qui est le plus légitime, les pétitionnaires ou les parlementaires ? | franceinfo', 'La pétition s\'opposant à la réintroduction d\'un pesticide, autorisée par la loi Duplomb, a recueilli plus d\'un million de signatures. Pas sûr que cela suffise à empêcher sa promulgation.', '', 0),
(6558, 'https://www.radiofrance.fr/franceinfo/podcasts/ca-dit-quoi/un-million-de-signatures-contre-un-pesticide-drogue-et-petites-villes-retour-des-hippies-ca-dit-quoi-ce-21-juillet-9912349', 'PODCAST. Un million de signatures contre un pesticide, drogue et petites villes, retour des hippies : ça dit quoi ce 21 juillet ? | franceinfo', 'Ce lundi 21 juillet, la pétition contre la loi Duplomb rassemble plus de 1,2 million de signatures de citoyens, plusieurs villes moyennes ont connu des violences urbaines liées au trafic de drogue, et les hippies de la \"Rainbow family\" s\'installent pour l\'été en Dordogne.', '', 0),
(6559, 'https://www.radiofrance.fr/franceinfo/podcasts/ils-ont-fait-l-actu/je-ne-regrette-rien-pres-d-un-an-apres-sa-non-nomination-lucie-castets-ne-reste-pas-amere-8598834', '\"Je ne regrette rien\" : près d\'un an après sa non-nomination, Lucie Castets ne reste pas amère | franceinfo', 'Le 23 juillet 2024, après seize jours d\'intenses négociations, le Nouveau Front populaire, arrivé en tête des législatives anticipées s\'accorde sur un nom pour le poste de Premier ministre, celui d\'une haute fonctionnaire, inconnue du grand public, Lucie Castets.', '', 0),
(6560, 'https://www.radiofrance.fr/franceculture/podcasts/journal-de-12h30/journal-de-12h30-du-lundi-21-juillet-2025-7888060', 'Loi Duplomb : la controverse ravivée par le succès de la pétition contre le texte | France Culture', 'Fort du succès de la pétition contre la loi Duplomb, la gauche et les écologistes ont promis de maintenir la pression à l\'automne autour de l\'abrogation du texte agricole décrié pour son impact environnemental.', '', 0),
(6561, 'https://www.radiofrance.fr/francebleu/podcasts/l-info-d-ici-ici-loire-ocean/je-suis-un-bulldozer-a-82-ans-l-iconique-vendeuse-de-maillots-de-bain-des-sables-d-olonne-ne-compte-pas-s-arreter-3534964', '\"Je suis un bulldozer\" : à 81 ans, l\'iconique vendeuse de maillots de bain des Sables-d\'Olonne ne compte pas s\'arrêter | ici', 'Comme l\'an passé, Léone Lefèvre n\'a pas prévu de prendre de vacances cet été. À 81 ans, l\'infatigable vendeuse tient d\'une main de fer le minuscule magasin de maillots de bain des Sables-d\'Olonne, \"Daisy Love\". Une aventure de 48 ans, entre prise d\'indépendance et impossibilité de raccrocher.', '', 0),
(6562, 'https://www.radiofrance.fr/franceinter/podcasts/blockbusters/blockbusters-du-lundi-21-juillet-2025-4286726', 'Denzel Washington : acteur capital | France Inter', 'Denzel Washington est souvent considéré comme l’acteur le plus classe du monde... \"Philadelphie\", \"Malcom X\", \"Training Day\", \"Man on Fire\", \"Hurricane Carter\" ! Porte-drapeau des acteurs Afro-américains, mais aussi parrain de toute une nouvelle génération d’acteurs. Denzel, c’est le boss !', '', 0),
(6563, 'https://www.radiofrance.fr/franceinter/podcasts/ou-est-ce-que-tu-vas-pour-les-vacances/ou-est-ce-que-tu-vas-pour-les-vacances-du-lundi-21-juillet-2025-2005576', 'Hyères-les-Palmiers, à la mode depuis le 19e siècle | France Inter', 'Aujourd’hui, direction Hyères-les-Palmiers ! On explore les rues de la station balnéaire du 19e siècle, et les plages de la presqu’île de Giens, et on profite des vues sur la ville et dans le ciel. Sans oublier un détour par la Villa Noailles, haut lieu d’art et de design.', '', 0),
(6564, 'https://www.radiofrance.fr/franceinfo/podcasts/la-releve/solann-entre-catharsis-et-combat-9094549', 'Solann, entre catharsis et combat | franceinfo', 'Tout l\'été, nous explorons le nouveau paysage des musiques populaires en France. Aujourd\'hui, une artiste à la plume sensible et tranchante, et dont la voix témoigne haut et fort d\'une vie de femme en ce siècle.', '', 0),
(6565, 'https://www.radiofrance.fr/franceinfo/podcasts/l-ete-des-chefs/bello-visto-a-gassin-vue-imprenable-sur-le-golfe-de-saint-tropez-5347390', 'Bello Visto, à Gassin : vue imprenable sur le golfe de Saint-Tropez | franceinfo', 'Si vous êtes en vacances dans le golfe de Saint-Tropez, voici les conseils de Bernard Thomasson pour trouver une bonne table dans ce coin du Var.', '', 0),
(6566, 'https://www.radiofrance.fr/franceinter/podcasts/canicule-sentimentale/canicule-sentimentale-du-lundi-21-juillet-2025-2166098', '\"Je suis chez les dingues\" : quand Marine est dépassée : épisode 6/10 du podcast Canicule sentimentale - Saison 2 - | France Inter', 'AUDIO • Canicule sentimentale - Saison 2 -, épisode 6/10 : \"Je suis chez les dingues\" : quand Marine est dépassée. Une série inédite proposée par France Inter. Écoutez Canicule sentimentale, et découvrez nos podcasts en ligne.', '', 0),
(6567, 'https://www.maisondelaradioetdelamusique.fr', 'Accueil | Maison de la radio et de la Musique', 'Lieu d\'expérience radiophonique et de partage de la culture ouvert tous les jours de 7h à 23h la Maison de la radio et de la musique propose des concerts de musique classique, des émissions de radio en public, des visites et des activités pour les classes et les familles', '', 0),
(6568, 'https://www.radiofrance.com/', 'Accueil | Radio France', 'Radio France 1er groupe radiophonique de service public et grande entreprise culturelle avec 7 radios nationales, 44 locales, 4 formations musicales', '', 0),
(6569, 'https://www.radiofrance.com/les-editions', 'Les Editions Radio France | Radio France', '', '', 0),
(6570, 'https://www.radiofrance.fr/personnes', 'Liste des personnalités et personnes morales | Radio France', 'Découvrez les biographies de milliers de personnalités publiques sur le site web de Radio France. Consultez les actualités liées à chacune d\'entre elles et explorez les personnes par ordre alphabétique.', '', 0),
(6571, 'https://www.radiofrance.fr/sujets', 'Liste de tous les sujets de A à Z | Radio France', 'Consultez la liste des catégories, tags et dossiers disponibles sur la plateforme web Radio France, classée par ordre alphabétique. Retrouvez les actualités liées à tous les sujets et découvrez des podcasts inédits.', '', 0),
(6572, 'https://www.radiofrance.fr/archives', 'Archives d\'actualités et podcasts – Radio France', 'Toutes les archives des émissions, podcasts et dossiers de Radio France. Parcourez les contenus par années, mois et dates spécifiques.', '', 0),
(6573, 'https://www.radiofrance.com/frequences', 'Frequences de nos antennes | Radio France', '', '', 0),
(6574, 'https://www.radiofrance.fr/index', 'Index | Radio France', '', '', 0),
(6575, 'https://www.radiofrance.fr/rss', 'Flux RSS Radio France', 'Flux RSS Radio France', '', 0),
