(6582, 'https://play.google.com/store/apps/details?id=com.radiofrance.radio.radiofrance.android&gl=FR', 'Radio France : radios, podcast - Apps on Google Play', 'Listen to the radio and all your podcasts, info, culture news & music unlimited.', '', 0),
(6583, 'https://apps.apple.com/fr/app/radio-france-podcast-radios/id310211433', 'âRadio France - podcast, direct dans lâApp Store', 'Lâapplication Radio France vous permet dâÃ©couter toutes les radios, les podcasts et la musique de France Inter, franceinfo, France Culture, France Bleu, Franceâ¦', 'Radio France - podcast, direct, Radio France, Musique,ActualitÃ©s, apps ios, app, appstore, app store, iphone, ipad, ipod touch, itouch, itunes', 0),
(6584, 'https://www.radiofrance.fr/franceinter/grille-programmes', 'Grille des programmes – France Inter', 'Consultez les programmes du jour et de la semaine sur France Inter. Retrouvez les horaires des émissions de radio, les sujets et les invités.', '', 0),
(6585, 'https://www.radiofrance.fr/franceinter/podcasts', 'Podcasts et émissions en replay – France Inter', 'Toutes les émissions et les chroniques de France Inter sont disponibles en replay. Écoutez vos émissions de radio favorites et des podcasts originaux.', '', 0),
(6586, 'https://www.radiofrance.fr/franceinter/podcasts/bouquet-s-informer-avec-inter', 'Toute l\'info d\'Inter  : actualités du jour et informations en replay par France Inter', 'Toute l\'actualité du jour est sur France Inter.', '', 0),
(6587, 'https://www.radiofrance.fr/franceinter/podcasts/bouquet-les-emissions-culturelles-d-inter', 'Toute la culture sur France Inter : derniers podcasts et émissions de France Inter', 'Les plus beaux moments culturels de l\'antenne sur France Inter.', '', 0),
(6588, 'https://www.radiofrance.fr/franceinter/podcasts/bouquet-l-humour-d-inter', 'Tout l\'humour d\'Inter : derniers podcasts et chroniques des humoristes de France Inter', 'L\'actu sous un autre angle. Drôles, critiques, parfois piquants, chaque jour nos chroniqueurs décapent l\'actualité.', '', 0),
(6589, 'https://www.radiofrance.fr/franceinter/podcasts/bouquet-les-emissions-musicales-d-inter', 'Toute la musique d\'Inter : derniers podcasts et concerts en replay de France Inter', 'La musique d\'Inter', '', 0),
(6590, 'https://www.radiofrance.fr/franceinter/podcasts/bouquet-au-quotidien-avec-inter', 'Toutes les émissions de Vie quotidienne de France Inter', 'Santé, famille, psycho, conso, bien-être... France Inter vous accompagne au quotidien.', '', 0),
(6591, 'https://www.radiofrance.fr/franceinter/la-musique-inter', 'La Musique d\'Inter : écoutez la playlist de France Inter', 'Écoutez la Musique d\'Inter : une programmation unique, des standards intemporels aux découvertes actuelles, 24h/24 et sans publicité.', '', 0),
(6592, 'https://www.radiofrance.fr/franceinter/direct', 'Écouter France Inter la radio en direct audio et vidéo', 'DIRECT. Écoutez et regardez le direct vidéo de votre radio France Inter. Toutes les infos, le programme des émissions, les sujets, les invités du jour.', '', 0),
